import { createTheme } from '@mui/material';

const getTheme = (mode) => {
  return createTheme({
    palette: {
      mode,
      primary: {
        main: '#1976d2',
        light: '#42a5f5',
        dark: '#1565c0',
      },
      secondary: {
        main: '#9c27b0',
        light: '#ba68c8',
        dark: '#7b1fa2',
      },
      success: {
        main: '#2e7d32',
        light: '#4caf50',
        dark: '#1b5e20',
      },
      error: {
        main: '#d32f2f',
        light: '#ef5350',
        dark: '#c62828',
      },
      background: {
        default: mode === 'dark' ? '#0a1929' : '#e7ebf0',
        paper: mode === 'dark' ? '#1a2027' : '#ffffff',
      },
      text: {
        primary: mode === 'dark' ? '#ffffff' : '#1a2027',
        secondary: mode === 'dark' ? '#b2bac2' : '#64748b',
      },
    },
    components: {
      MuiCard: {
        styleOverrides: {
          root: {
            borderRadius: 16,
            transition: 'all 0.2s cubic-bezier(0.4, 0, 0.2, 1)',
            boxShadow: mode === 'dark' 
              ? '0 2px 8px 0 rgba(0,0,0,0.4)'
              : '0 0 2px 0 rgba(145, 158, 171, 0.2), 0 12px 24px -4px rgba(145, 158, 171, 0.12)',
            '&:hover': {
              transform: 'translateY(-2px)',
              boxShadow: mode === 'dark'
                ? '0 8px 16px -4px rgba(0,0,0,0.5), 0 4px 12px 0 rgba(0,0,0,0.45)'
                : '0 0 2px 0 rgba(145, 158, 171, 0.2), 0 24px 32px -8px rgba(145, 158, 171, 0.24)',
            },
            backgroundColor: mode === 'dark' ? '#1a2027' : '#ffffff',
            backdropFilter: 'blur(20px)',
          },
        },
      },
      MuiCardContent: {
        styleOverrides: {
          root: {
            padding: '12px',
            '&:last-child': {
              paddingBottom: '12px',
            },
          },
        },
      },
      MuiButton: {
        styleOverrides: {
          root: {
            textTransform: 'none',
            borderRadius: 8,
            fontWeight: 600,
            padding: '4px 12px',
            boxShadow: 'none',
            '&:hover': {
              boxShadow: 'none',
            },
          },
          sizeSmall: {
            padding: '3px 8px',
            fontSize: '0.8125rem',
          },
        },
      },
      MuiLinearProgress: {
        styleOverrides: {
          root: {
            borderRadius: 4,
            backgroundColor: mode === 'dark' ? 'rgba(255, 255, 255, 0.08)' : 'rgba(0, 0, 0, 0.08)',
          },
          bar: {
            borderRadius: 4,
          },
        },
      },
      MuiCircularProgress: {
        styleOverrides: {
          root: {
            transition: 'all 0.3s ease',
          },
          circle: {
            strokeLinecap: 'round',
          },
        },
      },
      MuiTypography: {
        styleOverrides: {
          h5: {
            fontSize: '1.25rem',
            marginBottom: '0.5rem',
          },
          h6: {
            fontSize: '1rem',
            marginBottom: '0.5rem',
          },
          body2: {
            fontSize: '0.875rem',
            lineHeight: 1.4,
          },
        },
      },
      MuiStack: {
        defaultProps: {
          spacing: 1,
        },
      },
      MuiGrid: {
        defaultProps: {
          spacing: 1,
        },
      },
      MuiContainer: {
        styleOverrides: {
          root: {
            paddingLeft: '12px',
            paddingRight: '12px',
            '@media (min-width: 600px)': {
              paddingLeft: '16px',
              paddingRight: '16px',
            },
          },
        },
      },
      MuiDrawer: {
        styleOverrides: {
          paper: {
            backgroundColor: mode === 'dark' ? '#0a1929' : '#f3f6f9',
            borderRight: 'none',
          },
        },
      },
    },
    spacing: (factor) => `${0.5 * factor}rem`,
    shape: {
      borderRadius: 8,
    },
    typography: {
      fontFamily: [
        '-apple-system',
        'BlinkMacSystemFont',
        '"Segoe UI"',
        'Roboto',
        '"Helvetica Neue"',
        'Arial',
        'sans-serif',
      ].join(','),
      h5: {
        fontWeight: 600,
        fontSize: '1.25rem',
      },
      h6: {
        fontWeight: 600,
        fontSize: '1rem',
      },
      body2: {
        fontSize: '0.875rem',
      },
    },
  });
};

export default getTheme;
